// Stuff in here used to be in the standard library of signals -- see msynth-lib.ts
// But inlining them makes things more efficient b/c we don't have to pay for the
// overhead of lots of intermediate signals. (It matters for complex patches!)

import { InlinedModule } from "./module";

export const inlinedModules: Record<string, InlinedModule<any>> = {

  // ----- math stuff -----

  'unary-': InlinedModule.make(
    { x: '0' },
    (params) => `(-${params.x})`
  ),

  '+': InlinedModule.make(
    { x: '0', y: '0' },
    (params) => `(${params.x} + ${params.y})`
  ),

  '-': InlinedModule.make(
    { x: '0', y: '0' },
    (params) => `(${params.x} - ${params.y})`
  ),

  '*': InlinedModule.make(
    { x: '0', y: '0' },
    (params) => `(${params.x} * ${params.y})`
  ),

  '/': InlinedModule.make(
    { x: '0', y: '0' },
    (params) => `(${params.x} / ifZero(${params.y}, 0.00001))`
  ),

  '%': InlinedModule.make(
    { x: '0', y: '0' },
    (params) => `(${params.x} % ifZero(${params.y}, 0.00001))`
  ),

  clamp: InlinedModule.make(
    { input: '0', min: '0', max: '1' },
    (params) => `Math.min(Math.max(${params.input}, ${params.min}), ${params.max})`
  ),

  min: InlinedModule.make(
    { input: '0', y: '0' },
    (params) => `Math.min(${params.input}, ${params.y})`
  ),

  max: InlinedModule.make(
    { input: '0', y: '0' },
    (params) => `Math.max(${params.input}, ${params.y})`
  ),

  round: InlinedModule.make(
    { input: '0' },
    (params) => `Math.round(${params.input})`
  ),

  abs: InlinedModule.make(
    { input: '0' },
    (params) => `Math.abs(${params.input})`
  ),

  sqrt: InlinedModule.make(
    { input: '0' },
    (params) => `Math.sqrt(${params.input})`
  ),

  // ----- scaling -----

  /** [min, max] -> [0, 1], linearly */
  norm: InlinedModule.make(
    { input: '0', min: '-1', max: '1' },
    (params) => `((input, min, max) => max <= min ? 0 : (input - min) / (max - min))(${params.input}, ${params.min}, ${params.max})`,
  ),

  /** [0, 1] -> [min, max], linearly */
  scale: InlinedModule.make(
    { input: '0', min: '0', max: '1' },
    (params) => `((input, min, max) => input * (max - min) + min)(${params.input}, ${params.min}, ${params.max})`
  ),

  /** [0, 1] -> [min, max], exponentially */
  escale: InlinedModule.make(
    { input: '0', min: '0', max: '1' },
    (params) => `((input, min, max) => {
      if (min === 0) {
        min = 0.001;
      }
      return min * Math.pow(max / min, input);
    })(${params.input}, ${params.min}, ${params.max})`
  ),

  // ----- frequency helpers -----

  semitones: InlinedModule.make(
    { input: '0' },
    (params) => `Math.pow(2, ${params.input} / 12)`
  ),

  quantizeFreq: InlinedModule.make(
    { input: '0', base: '440' },
    (params) => `((input, base) => (base * Math.pow(2, Math.round(12 * Math.log2(input / base)) / 12)))(${params.input}, ${params.base})`
  ),

  // ----- conditionals -----

  switch2: InlinedModule.make(
    { input: '0', pos: '0', neg: '0' },
    (params) => `(${params.input} >= 0 ? ${params.pos} : ${params.neg})`
  ),

  switch3: InlinedModule.make(
    { input: '0', neg: '0', zero: '0', pos: '0' },
    (params) => `((input, neg, zero, pos) => input === 0 ? zero : input < 0 ? neg : pos)(${params.input}, ${params.neg}, ${params.zero}, ${params.pos})`
  ),

  // ----- effects -----

  softClip: InlinedModule.make(
    { input: '0' },
    (params) => `((input) => input <= -1 ? -2/3 : input >= 1 ? 2/3 : input - input ** 3 / 3)(${params.input})`
  ),
};
