import { TAU, SAMPLE_RATE, SAMPLE_RATE_RECIP, AI_MODULES_KEY } from './constants';
import { Module } from "./module";
import { Signal, scalar } from './signal';
import { transform } from "sucrase";
import { generateModuleCode } from './generate-module-code';

let _aiModules: Record<string, Module<any>> = {};

let lastLoaded = '';

export function loadAiModules(tsSource = localStorage.getItem(AI_MODULES_KEY)) {
  if (tsSource !== lastLoaded) {
    console.log('loading ai modules', tsSource);
    _aiModules = {};
    loadAiModule(tsSource);
    lastLoaded = tsSource;
  }
  return _aiModules;
}

function loadAiModule(tsSource: string): string {
  const jsSource = transform(tsSource, {
    transforms: ['typescript'],
  }).code;
  const fn = new Function('addAiModule', 'Module', 'TAU', 'SAMPLE_RATE', 'SAMPLE_RATE_RECIP', 'Signal', 'scalar', jsSource);
  return fn(addAiModule, Module, TAU, SAMPLE_RATE, SAMPLE_RATE_RECIP, Signal, scalar);
}

/** This function is called by AI-generated code. */
export function addAiModule(name: string, module: Module<any>): string {
  console.log('adding ai module', name);
  _aiModules[name] = module;
  return name;
}

export async function generateModule(prompt: string) {
  try {
    const tsCode = await generateModuleCode(prompt);
    const name = loadAiModule('return ' + tsCode);
    localStorage.setItem(AI_MODULES_KEY, localStorage.getItem(AI_MODULES_KEY) + '\n\n' + tsCode);
    return name;
  } catch (e) {
    console.error('Error loading AI module', e);
    return `Error loading AI module: ${e.message}`;
  }
}
