import { SAMPLE_RATE, SAMPLE_RATE_RECIP } from './constants';
import { Signal } from './signal';

export function ad(input: Signal, a: Signal, d: Signal) {
  let stage: 'off' | 'a' | 'd' = 'off';
  let envValue = 0;
  return Signal.new({
    nextSample() {
      switch (stage) {
        case 'off':
          envValue = 0;
          break;
        case 'a':
          envValue = a.value > 0 ? Math.min(envValue + SAMPLE_RATE_RECIP / a.value, 1) : 1;
          if (envValue === 1) {
            stage = 'd';
          }
          break;
        case 'd':
          envValue = d.value > 0 ? Math.max(envValue - SAMPLE_RATE_RECIP / d.value, 0) : 0;
          if (envValue === 0) {
            stage = 'off';
          }
          break;
      }
      return envValue * input.value;
    },

    initialValue: 0,

    noteOn() {
      stage = 'a';
      // note: don't set envValue to zero, otherwise we get clicks
      // when the env is triggered halfway through the previous time
    },
  });
}

export function adsr(input: Signal, a: Signal, d: Signal, s: Signal, r: Signal) {
  let stage: 'off' | 'a' | 'd' | 's' | 'r' = 'off';
  let envValue = 0;
  return Signal.new({
    nextSample() {
      switch (stage) {
        case 'off':
          envValue = 0;
          break;
        case 'a':
          envValue = a.value > 0 ? Math.min(envValue + SAMPLE_RATE_RECIP / a.value, 1) : 1;
          if (envValue === 1) {
            stage = 'd';
          }
          break;
        case 'd':
          envValue = d.value > 0 ? Math.max(envValue - SAMPLE_RATE_RECIP / d.value, s.value) : s.value;
          if (envValue === s.value) {
            stage = 's';
          }
          break;
        case 's':
          break;
        case 'r':
          envValue = r.value > 0 ? Math.max(envValue - SAMPLE_RATE_RECIP / r.value, 0) : 0;
          if (envValue === 0) {
            stage = 'off';
          }
          break;
      }
      return envValue * input.value;
    },

    initialValue: 0,

    noteOn() {
      stage = 'a';
      // note: don't set the value to zero, otherwise we get clicks
      // when the env is triggered halfway through the previous time
    },

    noteOff() {
      stage = 'r';
    },
  });
}

export function gate(input: Signal, t: Signal) {
  let stage: 'on' | 'off' = 'off';
  let count = 0;
  return Signal.new({
    nextSample() {
      let envValue: number;
      switch (stage) {
        case 'off':
          envValue = 0;
          break;
        case 'on':
          if (t.value > 0 && count++ >= t.value * SAMPLE_RATE) {
            stage = 'off';
            envValue = 0;
          } else {
            envValue = 1;
          }
          break;
      }
      return envValue * input.value;
    },

    initialValue: 0,

    noteOn() {
      stage = 'on';
      count = 0;
    },

    noteOff() {
      if (!t) {
        stage = 'off';
      }
    },
  });
}
