const uiDiv = document.getElementById('ui') as HTMLDivElement;

export const canvas = document.createElement('canvas');
export const ctx = canvas.getContext('2d')!;
uiDiv.appendChild(canvas);

function resize() {
  // Match the canvas's CSS size to the viewport
  canvas.style.width = innerWidth + 'px';
  canvas.style.height = innerHeight + 'px';

  // Set the internal pixel dimensions of the canvas
  canvas.width = innerWidth * devicePixelRatio;
  canvas.height = innerHeight * devicePixelRatio;

  // Reset any previous transform and apply the correct scaling.
  // Using setTransform avoids compounding the scale on repeated resizes.
  ctx.setTransform(devicePixelRatio, 0, 0, devicePixelRatio, 0, 0);
}

window.addEventListener('resize', resize);
resize();

