const STATUS_LINGER_TIME_MS = 2_000;
let status = '';
let statusTime = 0;

export function showStatus(msg: string) {
  status = msg;
  statusTime = Date.now();
}

export function renderStatus() {
  if (status.length > 0 && Date.now() - statusTime < STATUS_LINGER_TIME_MS) {
    ctx.save();
    ctx.font = '16px monospace';
    const { width } = ctx.measureText(status);
    const x = innerWidth - width - 20;
    const y = innerHeight - 20;
    ctx.fillStyle = '#00a';
    ctx.fillText(status, x, y);
    ctx.restore();
  }
}
